function resizeProfileImage(file) { return new Promise((resolve, reject) => { const reader = new FileReader(); reader.onerror = () => reject(new Error('No se pudo leer la imagen.')); reader.onload = () => { const image = new Image(); image.onerror = () => reject(new Error('La imagen no es válida.')); image.onload = () => { const size = 512, scale = Math.max(size / image.width, size / image.height), width = Math.round(image.width * scale), height = Math.round(image.height * scale), canvas = document.createElement('canvas'); canvas.width = size; canvas.height = size; const context = canvas.getContext('2d'); context.drawImage(image, (size - width) / 2, (size - height) / 2, width, height); resolve(canvas.toDataURL('image/jpeg', .84)); }; image.src = reader.result; }; reader.readAsDataURL(file); }); }
